queries.sparql:
PREFIX : <http://ambrosia.example.org/jobpostings#>
PREFIX p: <http://ambrosia.example.org/jobpostings/prop#>
PREFIX xsd: <http://www.w3.org/2001/XMLSchema#>
SELECT DISTINCT ?o0 WHERE {
  {
    ?interior_designers a :Interior_Designers .
    ?interior_designers p:name ?name .
    ?interior_designers p:Style ?style_f .
    FILTER(STR(?style_f) = "Minimalism")
    BIND(?name AS ?o0)
  }
  UNION
  {
    ?landscape_architects a :Landscape_Architects .
    ?landscape_architects p:name ?name .
    ?landscape_architects p:Style ?style_f .
    FILTER(STR(?style_f) = "Minimalism")
    BIND(?name AS ?o0)
  }
}

